#include <iostream>
#include <string>

// A simple class template representing a generic 2D coordinate
template <typename T>
class Point2D {
private:
    T x;
    T y;
public:
    Point2D(T xVal, T yVal) : x(xVal), y(yVal) {}

    T getX() const { return x; }
    T getY() const { return y; }

    void display() const {
        std::cout << "Point(" << x << ", " << y << ")\n";
    }
};

int main() {
    // Explicit instantiation with int
    Point2D<int> intPoint(5, 10);
    intPoint.display();

    // C++17 Class Template Argument Deduction (CTAD) with double
    Point2D doublePoint(3.14, 2.71);
    doublePoint.display();

    // Instantiation with std::string
    Point2D<std::string> stringPoint("Alpha", "Beta");
    stringPoint.display();

    return 0;
}

Code Example 2 (Practical):
#include <iostream>
#include <type_traits>

// Primary Class Template
template <typename T>
class SmartStorage {
private:
    T value;
public:
    SmartStorage(T val) : value(val) {
        // Enforce that we do not use raw pointers in the primary template
        static_assert(!std::is_pointer_v<T>, "Use the pointer specialization for raw pointers!");
    }

    void display() const {
        std::cout << "Value: " << value << "\n";
    }
};

// Full Specialization for raw pointers to prevent printing raw memory addresses
template <typename T>
class SmartStorage<T*> {
private:
    T* ptr;
public:
    SmartStorage(T* p) : ptr(p) {}

    void display() const {
        if (ptr) {
            std::cout << "Pointed Value: " << *ptr << "\n";
        } else {
            std::cout << "Pointer is null\n";
        }
    }
};

int main() {
    int num = 42;

    // Instantiates primary template SmartStorage<int>
    SmartStorage<int> normalStorage(num);
    normalStorage.display();

    // Instantiates specialized template SmartStorage<int*>
    SmartStorage<int*> pointerStorage(&num);
    pointerStorage.display();

    return 0;
}

