template <typename T>
class Registry {
private:
    T value;
public:
    Registry(T val) : value(val) {}

    T cloneValue() const {
        if constexpr (std::is_copy_constructible_v<T>) {
            return value;
        } else {
            static_assert(std::is_copy_constructible_v<T>, "Type is not copy-constructible!");
        }
    }
};

